const AgentBookkeeper = () => {
  const [transactions, setTransactions] = React.useState([
    { id: 1, date: '2024-01-15', desc: 'Office supplies', amount: -124.50, category: 'expense' },
    { id: 2, date: '2024-01-14', desc: 'Client payment', amount: 2500.00, category: 'revenue' },
    { id: 3, date: '2024-01-12', desc: 'Software subscription', amount: -49.99, category: 'expense' },
    { id: 4, date: '2024-01-10', desc: 'Consulting fee', amount: 1800.00, category: 'revenue' },
    { id: 5, date: '2024-01-08', desc: 'Utilities', amount: -210.30, category: 'expense' }
  ]);
  const [form, setForm] = React.useState({ desc: '', amount: '', category: 'expense' });
  const [filter, setFilter] = React.useState('all');

  const addTransaction = () => {
    if (!form.desc || !form.amount) return;
    const amt = form.category === 'expense' ? -Math.abs(Number(form.amount)) : Math.abs(Number(form.amount));
    setTransactions([{ id: Date.now(), date: new Date().toISOString().slice(0, 10), desc: form.desc, amount: amt, category: form.category }, ...transactions]);
    setForm({ desc: '', amount: '', category: 'expense' });
  };

  const revenue = transactions.filter(t => t.amount > 0).reduce((a, b) => a + b.amount, 0);
  const expenses = transactions.filter(t => t.amount < 0).reduce((a, b) => a + b.amount, 0);
  const net = revenue + expenses;

  const filtered = filter === 'all' ? transactions : transactions.filter(t => t.category === filter);

  const catColors = { revenue: '#16a34a', expense: '#dc2626' };

  return React.createElement('div', { style: { fontFamily: 'system-ui, sans-serif', padding: '16px', display: 'flex', flexDirection: 'column', gap: '16px', height: '100%', overflow: 'auto' } },
    React.createElement('h3', { style: { margin: 0, fontSize: '16px', fontWeight: 600, color: '#111827' } }, 'Bookkeeper'),
    React.createElement('div', { style: { display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '8px' } },
      React.createElement('div', { style: { background: '#f0fdf4', borderRadius: '8px', padding: '12px', textAlign: 'center' } },
        React.createElement('div', { style: { fontSize: '11px', color: '#16a34a', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.05em' } }, 'Revenue'),
        React.createElement('div', { style: { fontSize: '18px', fontWeight: 700, color: '#16a34a' } }, '+', revenue.toFixed(2))
      ),
      React.createElement('div', { style: { background: '#fef2f2', borderRadius: '8px', padding: '12px', textAlign: 'center' } },
        React.createElement('div', { style: { fontSize: '11px', color: '#dc2626', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.05em' } }, 'Expenses'),
        React.createElement('div', { style: { fontSize: '18px', fontWeight: 700, color: '#dc2626' } }, expenses.toFixed(2))
      ),
      React.createElement('div', { style: { background: net >= 0 ? '#f0fdf4' : '#fef2f2', borderRadius: '8px', padding: '12px', textAlign: 'center' } },
        React.createElement('div', { style: { fontSize: '11px', color: net >= 0 ? '#16a34a' : '#dc2626', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.05em' } }, 'Net'),
        React.createElement('div', { style: { fontSize: '18px', fontWeight: 700, color: net >= 0 ? '#16a34a' : '#dc2626' } }, net.toFixed(2))
      )
    ),
    React.createElement('div', { style: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' } },
      React.createElement('div', { style: { background: '#f9fafb', borderRadius: '8px', padding: '12px', display: 'flex', flexDirection: 'column', gap: '8px' } },
        React.createElement('div', { style: { fontSize: '12px', fontWeight: 600, color: '#6b7280', marginBottom: '4px', textTransform: 'uppercase', letterSpacing: '0.05em' } }, 'Add Transaction'),
        React.createElement('input', { value: form.desc, onChange: e => setForm({ ...form, desc: e.target.value }), placeholder: 'Description', style: { fontSize: '12px', padding: '6px', borderRadius: '4px', border: '1px solid #d1d5db' } }),
        React.createElement('input', { type: 'number', value: form.amount, onChange: e => setForm({ ...form, amount: e.target.value }), placeholder: 'Amount', style: { fontSize: '12px', padding: '6px', borderRadius: '4px', border: '1px solid #d1d5db' } }),
        React.createElement('select', { value: form.category, onChange: e => setForm({ ...form, category: e.target.value }), style: { fontSize: '12px', padding: '6px', borderRadius: '4px', border: '1px solid #d1d5db' } },
          React.createElement('option', { value: 'revenue' }, 'Revenue'),
          React.createElement('option', { value: 'expense' }, 'Expense')
        ),
        React.createElement('button', { onClick: addTransaction, style: { fontSize: '12px', padding: '8px', borderRadius: '4px', border: 'none', background: '#2563eb', color: '#fff', cursor: 'pointer', fontWeight: 600 } }, 'Add')
      ),
      React.createElement('div', { style: { background: '#f9fafb', borderRadius: '8px', padding: '12px', display: 'flex', flexDirection: 'column', gap: '8px' } },
        React.createElement('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center' } },
          React.createElement('div', { style: { fontSize: '12px', fontWeight: 600, color: '#6b7280', textTransform: 'uppercase', letterSpacing: '0.05em' } }, 'Transactions'),
          React.createElement('select', { value: filter, onChange: e => setFilter(e.target.value), style: { fontSize: '11px', padding: '4px', borderRadius: '4px', border: '1px solid #d1d5db' } },
            React.createElement('option', { value: 'all' }, 'All'),
            React.createElement('option', { value: 'revenue' }, 'Revenue'),
            React.createElement('option', { value: 'expense' }, 'Expense')
          )
        ),
        React.createElement('div', { style: { display: 'flex', flexDirection: 'column', gap: '6px', overflow: 'auto' } },
          filtered.map(t => React.createElement('div', { key: t.id, style: { background: '#fff', borderRadius: '6px', padding: '8px', border: '1px solid #e5e7eb', display: 'flex', justifyContent: 'space-between', alignItems: 'center' } },
            React.createElement('div', null,
              React.createElement('div', { style: { fontWeight: 600, fontSize: '12px', color: '#111827' } }, t.desc),
              React.createElement('div', { style: { fontSize: '11px', color: '#9ca3af' } }, t.date, ' ', React.createElement('span', { style: { color: catColors[t.category], fontWeight: 600, textTransform: 'uppercase', fontSize: '10px' } }, t.category))
            ),
            React.createElement('span', { style: { fontSize: '13px', fontWeight: 700, color: t.amount > 0 ? '#16a34a' : '#dc2626' } }, t.amount > 0 ? '+' : '', t.amount.toFixed(2))
          ))
        )
      )
    )
  );
};
render(<AgentBookkeeper/>);
